queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?column_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasColumns ?child ; p:hasNewspapers ?parent . } GROUP BY ?child }
  ?child p:column_name ?column_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Newspapers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?column_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasColumns ?child ; p:hasNewspapers ?parent . } GROUP BY ?child }
  ?child p:column_name ?column_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Newspapers } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?column_name WHERE {
  ?newspapers_columns a :Newspapers_Columns .
  ?columns a :Columns .
  ?newspapers_columns p:hasColumns ?columns .
  ?newspapers a :Newspapers .
  ?newspapers_columns p:hasNewspapers ?newspapers .
  ?newspapers p:name ?name .
  ?columns p:column_name ?column_name .
} }
}
